INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00891', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '孝子何珍，字嵩山，高明人。幼喜讀書，以父母不見為恨，遂絕意功名。每日必慟，不兼味，人稱一味孝子 （《廣東新語》）。依據上文，下列選項敘述正確的是：', '["他怕做官後無法常見到父母，所以不願去應考", "他因擔心每天見不到父母，所以無心享受美食", "他每天只吃一道菜，想省下錢來好好孝敬父母", "他因思念父母而十分悲痛，無心追求飲食豐美"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00892', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '《荀子．勸學》：「螣蛇無足而飛，鼫鼠五技而窮。」下列選項何者最符合引文意旨？', '["天生我材，必有所用", "用心專一，必能成功", "教育長養，適才適性", "鯉躍龍門，一朝飛天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00893', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '人有亡鈇者，意其鄰之子，視其行步，竊鈇也；顏色，竊鈇也；言語，竊鈇也；動作態度，無為而不竊鈇也。 俄而掘其谷而得其鈇，他日復見其鄰人之子，動作態度無似竊鈇者（《列子．說符》）。根據文意，下列何 者正確？', '["竊賊不是鄰人之子", "竊賊心虛，易形於色", "竊賊將竊物埋藏於谷中", "被竊者自導自演，以考驗人性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00894', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '《封神演義》：「旛幢招展，三春楊柳交加；號帶飄揚，七夕彩雲蔽日。刀鎗閃灼，三冬瑞雪重鋪；劍戟森 嚴，九月秋霜蓋地。」下列選項，何者最符合上文所描述的場景？', '["歲時節慶", "兩軍對陣", "四時風光", "萬里江山"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00895', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '荊人有遺弓者，而不肯索。曰：「荊人遺之，荊人得之，又何索焉？」孔子聞之，曰：「去其『荊』而可矣。」 老聃聞之，曰：「去其『人』而可矣。」故老聃則至公矣（《呂氏春秋．貴公》）。根據文意，下列何者正 確？', '["天下之物，本無得失", "差之毫釐，失之千里", "名正言順，天下乃安", "君子不器，各適其用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00896', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '《荀子．勸學》：「不積蹞步，無以至千里；不積小流，無以成江海。」下列選項最符合本文意旨的是：', '["學而時習之，不亦說乎", "學然後知不足，教然後知困", "真積力久則入，學至乎沒而後止也", "一日暴之，十日寒之，未有能生者也"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00897', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '「這期間我看到了一些怵目驚心的文字，譬如說一位經營文藝出版社的朋友這樣寫：『賣書和賣鑽石一 樣……。』我不懂意思，不禁在心中犯嘀咕：『鑽石和書怎麼做比較？』繼續讀下去，才知道他的意思是： 『鑽石價錢昂貴，一個月有那麼幾筆生意就很不錯了。現在賣書也那樣，一個月就只有那麼幾筆。』」下列 何者最符合作者所要表達的意思？', '["讚嘆文藝的可貴", "驚奇書價的昂貴", "感嘆文藝出版的蕭條", "不解讀書風氣的敗壞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00898', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '「魚類與鯨豚這兩樣海洋生物資源之豐寡，與背後支撐整個海洋生態系統的海洋環境密切相關。然而，臺灣 社會與海洋生物資源的關係，長期停滯在低層次的腸胃等級。我們過度漁撈，我們隨手將污染擴及海域，造 成東部沿海的魚源處於近臨枯竭的狀態。鯨豚失去食物基礎支撐，快速且大幅減少，因其生態位階高，跌落 更快、更慘。」下列選項何者不是鯨豚數量減少的原因？', '["人類的污染擴大", "鯨豚繁衍能力差", "漁民過度的捕撈", "失去食物鏈基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00899', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '「我靜坐水湄一隅，瞧！蘆葦□□著身子，頂著一頭□□般的髮。是由於負荷了過重的鄉思而壓彎了脊樑？ 是因著朝夕守望而愁白了頭嚒？」根據文意，文中的□□依序應是：', '["挺立／青絲", "傾斜／蓬草", "佝僂／銀絲", "搖曳／枯柳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00900', 'elementary-acfc4025', 'elementary-acfc4025-moex-110-01c5eaab', 'sub-elementary-acfc4025-05', NULL, 'single_choice', '下列題辭用語，何者適當？', '["「于歸之喜」：慶賀遷居", "「瓜瓞延祥」：慶賀生孫", "「母儀足式」：慶賀女壽", "「弄璋誌喜」：慶賀生女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
